# Concrete shape implementations and shape collections
from data_models import ShapeBase, IShape, Point, Metrics, ShapeType

class Circle(ShapeBase, IShape):
    radius: float

    def __init__(self, name: str, pos: Point, radius: float):
        super().__init__(name, pos)
        self.radius = radius

    @override
    def describe(self) -> str:
        return "Circle '" + self.name + "' at (" + str(self.position.x) + ", " + str(self.position.y) + ")"

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def get_shape_type(self) -> ShapeType:
        return ShapeType.CIRCLE

    @override
    def calculate_metrics(self) -> Metrics:
        return Metrics(self.area(), self.perimeter())

class Rectangle(ShapeBase, IShape):
    width: float
    height: float

    def __init__(self, name: str, pos: Point, width: float, height: float):
        super().__init__(name, pos)
        self.width = width
        self.height = height

    @override
    def describe(self) -> str:
        return "Rectangle '" + self.name + "' size " + str(self.width) + "x" + str(self.height)

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def get_shape_type(self) -> ShapeType:
        return ShapeType.RECTANGLE

    @override
    def calculate_metrics(self) -> Metrics:
        return Metrics(self.area(), self.perimeter())

    def is_square(self) -> bool:
        return self.width == self.height

class ShapeCollection:
    shapes: list[IShape]
    total_area: float

    def __init__(self):
        self.shapes = []
        self.total_area = 0.0

    def add(self, shape: IShape) -> None:
        self.shapes.append(shape)

    def total_area_calculated(self) -> float:
        total: float = 0.0
        for s in self.shapes:
            total += s.area()
        return total

    def count_by_type(self, stype: ShapeType) -> int:
        count: int = 0
        for s in self.shapes:
            if s.get_shape_type() == stype:
                count += 1
        return count

    def get_all_descriptions(self) -> list[str]:
        result: list[str] = []
        for s in self.shapes:
            if isinstance(s, ShapeBase):
                result.append(s.describe())
        return result

