# Utility functions and helpers
from operations import Circle, Rectangle
from data_models import Point, ShapeType

def make_circle_at_origin(name: str, radius: float) -> Circle:
    origin: Point = Point(0.0, 0.0)
    return Circle(name, origin, radius)

def make_rectangle_at(x: float, y: float, name: str, width: float, height: float) -> Rectangle:
    pos: Point = Point(x, y)
    return Rectangle(name, pos, width, height)

def format_area(area: float) -> str:
    return "Area: " + str(area)

def shape_type_name(st: ShapeType) -> str:
    if st == ShapeType.CIRCLE:
        return "Circle"
    elif st == ShapeType.RECTANGLE:
        return "Rectangle"
    else:
        return "Other"

def sum_areas(shapes: list[Circle]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.area()
    return total
